arguments.new_str:
using System;
using System.Numerics;
using System.Runtime.InteropServices;

namespace IntConditionalInc;

public class ConditionalIncrement
{
    public static void IncrementAbove(Span<int> data, int threshold)
    {
        if (Vector.IsHardwareAccelerated && data.Length >= Vector<int>.Count)
        {
            var thresholdVec = new Vector<int>(threshold);
            var vectors = MemoryMarshal.Cast<int, Vector<int>>(data);

            for (int i = 0; i < vectors.Length; i++)
            {
                // GreaterThan returns -1 per lane where true; subtracting -1 adds 1.
                vectors[i] -= Vector.GreaterThan(vectors[i], thresholdVec);
            }

            // Scalar tail for remaining elements not filling a full vector.
            for (int i = vectors.Length * Vector<int>.Count; i < data.Length; i++)
            {
                if (data[i] > threshold)
                    data[i]++;
            }
        }
        else
        {
            for (int i = 0; i < data.Length; i++)
            {
                if (data[i] > threshold)
                    data[i]++;
            }
        }
    }
}

